class BatchJob:
    id: str
    format: str
    max_mb: float = 1.0
    edits: EditOptions = field(default_factory=EditOptions)
    strip_metadata: bool = True
    apply_orientation: bool = True
    preset_name: str | None = None
    status: JobStatus = JobStatus.QUEUED
    created_at: float = field(default_factory=time.time)
    updated_at: float = field(default_factory=time.time)
    items: list[QueueItem] = field(default_factory=list)
    position: int | None = None

    @property
    def total(self) -> int:
        return len(self.items)

    @property
    def completed_count(self) -> int:
        return sum(1 for item in self.items if item.status == ItemStatus.COMPLETED)

    @property
    def failed_count(self) -> int:
        return sum(1 for item in self.items if item.status == ItemStatus.FAILED)

    @property
    def pending_count(self) -> int:
        return sum(1 for item in self.items if item.status == ItemStatus.PENDING)

    @property
    def processing_count(self) -> int:
        return sum(1 for item in self.items if item.status == ItemStatus.PROCESSING)

